    // Wait for error state
    await expect(page.locator("[data-testid=error-state]")).toBeVisible();
    console.log("[E2E] Error state shown after first failed request");

    // Find and click retry button
    const retryButton = page.locator("button:has-text(\"Retry\"), button:has-text(\"Try Again\")");
    await expect(retryButton).toBeVisible();
    console.log("[E2E] Retry button is visible");

    await retryButton.click();
    console.log("[E2E] Clicked retry button");

    // Wait for success state
    await expect(page.locator("[data-testid=error-state]")).not.toBeVisible({ timeout: 5000 });
    console.log("[E2E] Error state cleared after retry");

    expect(apiCallCount).toBe(2);
    await page.screenshot({ path: "e2e-screenshots/api-retry-success.png" });
    console.log("[E2E] PASS: Retry mechanism works");
  });

  test("should show retry button after multiple failures", async ({ page }) => {
    await page.route("**/api/**", route => route.fulfill({ status: 500 }));

    await page.goto("/dashboard");

    // Click retry multiple times
    for (let i = 0; i < 3; i++) {
      await expect(page.locator("[data-testid=error-state]")).toBeVisible();
      const retryButton = page.locator("button:has-text(\"Retry\")");
